190	func (s *BookingService) TransitionBooking(bookingID uint, newStatus models.BookingStatus, changedBy uint, note string) error {
191		var booking models.Booking
192		if err := s.DB.First(&booking, bookingID).Error; err != nil {
193			return err
194		}
195	
196		// Validate state transition
197		valid := map[models.BookingStatus][]models.BookingStatus{
198			models.BookingInitiated: {models.BookingConfirmed, models.BookingCanceled},
199			models.BookingConfirmed: {models.BookingCanceled},
200			models.BookingCanceled:  {models.BookingRefunded},
201		}
202	
203		allowed, ok := valid[booking.Status]
204		if !ok {
205			return errors.New("booking is in a terminal state")
206		}
207	
208		isAllowed := false
209		for _, s := range allowed {
210			if s == newStatus {
211				isAllowed = true
212				break
213			}
214		}
215		if !isAllowed {
216			return errors.New("invalid state transition")
217		}
218	
219		// Enforce 2-hour cancellation rule
220		if newStatus == models.BookingCanceled {
221			if time.Until(booking.SlotStart) < 2*time.Hour {
222				return errors.New("cannot cancel less than 2 hours before the session")
223			}
224		}
225	
226		oldStatus := booking.Status
227		err := s.DB.Transaction(func(tx *gorm.DB) error {
228			booking.Status = newStatus
229			if err := tx.Save(&booking).Error; err != nil {
230				return err
231			}
232			return tx.Create(&models.BookingAudit{
233				BookingID: bookingID,
234				ChangedBy: changedBy,
235				OldStatus: string(oldStatus),
236				NewStatus: string(newStatus),
237				Note:      note,
238				Timestamp: time.Now(),
239			}).Error
240		})
241	
242		if err == nil && s.Webhook != nil {
243			eventType := "booking." + string(newStatus)
244			s.Webhook.DispatchForOrg(eventType, map[string]interface{}{
245				"booking_id": bookingID, "old_status": string(oldStatus),
246				"new_status": string(newStatus), "changed_by": changedBy, "note": note,
247			}, booking.OrganizationID)
248		}
