309	func (s *WebhookService) deliver(endpoint models.WebhookEndpoint, payload []byte) {
310		// Delivery-time revalidation: ensure target is still internal
311		if !IsInternalURL(endpoint.URL) {
312			s.logDelivery(endpoint.ID, string(payload), 0, "delivery blocked: non-internal URL", 1)
313			return
314		}
315		// Sign the payload once (payload bytes are immutable)
316		mac := hmac.New(sha256.New, []byte(endpoint.Secret))
317		mac.Write(payload)
318		signature := hex.EncodeToString(mac.Sum(nil))
319	
320		maxRetries := 3
321		for attempt := 1; attempt <= maxRetries; attempt++ {
322			// Create a FRESH request with a new body reader on every attempt
323			req, err := http.NewRequest("POST", endpoint.URL, bytes.NewReader(payload))
324			if err != nil {
325				s.logDelivery(endpoint.ID, string(payload), 0, err.Error(), attempt)
326				return
327			}
328			req.Header.Set("Content-Type", "application/json")
329			req.Header.Set("X-Webhook-Signature", signature)
330			req.Header.Set("X-Webhook-Event", endpoint.EventType)
331	
332			resp, err := s.client.Do(req)
333			if err != nil {
334				if attempt == maxRetries {
335					s.logDelivery(endpoint.ID, string(payload), 0, err.Error(), attempt)
336				}
337				time.Sleep(time.Duration(attempt) * time.Second)
338				continue
339			}
340			resp.Body.Close()
341			s.logDelivery(endpoint.ID, string(payload), resp.StatusCode, "", attempt)
342			return
343		}
344	}
